CREATE OR REPLACE FUNCTION fpa_kep_count_item_type (ai_year integer,ai_month integer,as_memno char,ai_seqno integer) RETURNS bigint AS $body$
DECLARE

  li_count bigint;

BEGIN
  select count(keeping_type_code) into STRICT  li_count
  from   sc_kep_t_monthly_receive_det
  where (receive_month = ai_month)
  and (receive_year = ai_year)
  and (seq_no= ai_seqno)
  and (membership_no = as_memno)
  and (mpost_money_amount > 0 );

return   li_count;

exception when others then CALL spa_dberror('fpa_kep_count_item_type');
END;
$body$
LANGUAGE PLPGSQL
